  if (s.includes("maturing")) return "#3b82f6";
  if (s.includes("watch")) return "#f59e0b";
  if (s.includes("at-risk") || s.includes("at risk")) return "#ef4444";
  if (s.includes("archived")) return "#6b7280";
  return "#6b7280";
}
